changeSet.sql:
INSERT IGNORE INTO role_template_permissions (template_id, permission_id) VALUES (1, 77), (1, 78);
INSERT IGNORE INTO role_template_assignable_permissions (template_id, permission_id) VALUES (1, 77), (1, 78);

INSERT IGNORE INTO role_permissions (role_id, permission_id)
SELECT r.id, p.id
FROM roles r
JOIN permissions p ON p.code IN ('expense.view', 'expense.manage')
WHERE r.name = 'ADMIN';

INSERT IGNORE INTO role_assignable_permissions (role_id, permission_id)
SELECT r.id, p.id
FROM roles r
JOIN permissions p ON p.code IN ('expense.view', 'expense.manage')
WHERE r.name = 'ADMIN';
